// BR-17: Input Validation
const data = $input.first().json;
const binaryData = $input.first().binary || {};

const errors = [];

if (!binaryData.jobFile && !data.jobFile) {
  errors.push('Job Description file is missing or empty.');
}
if (!binaryData.resumeFile && !data.resumeFile) {
  errors.push('Resume file is missing or empty.');
}

if (errors.length > 0) {
  throw new Error('Validation Failed: ' + errors.join(' | '));
}

return $input.all();

const item = $input.first().json;
const raw = item.text || item.data || item.content || '';
return [{ json: { text: raw } }];

const item = $input.first().json;
const raw = item.text || item.data || item.content || '';
return [{ json: { text: raw } }];

// FAILURE PATH GUARD — Job Analyzer
const item = $input.first().json;

const role            = item.role            || (item.output && item.output.role)            || null;
const skills_required = item.skills_required || (item.output && item.output.skills_required) || null;

if (!role || !skills_required || !Array.isArray(skills_required) || skills_required.length === 0) {
  throw new Error(
    'Job Analyzer produced invalid output. ' +
    'role=' + JSON.stringify(role) + ' ' +
    'skills_required=' + JSON.stringify(skills_required) + '. ' +
    'Check that the job description file extracted correctly and the LLM returned valid JSON.'
  );
}

return [{ json: item }];

// FAILURE PATH GUARD — Resume Analyzer
const item = $input.first().json;

const name   = item.name   || (item.output && item.output.name)   || null;
const skills = item.skills || (item.output && item.output.skills) || null;

if (!name || !skills || !Array.isArray(skills) || skills.length === 0) {
  throw new Error(
    'Resume Analyzer produced invalid output. ' +
    'name=' + JSON.stringify(name) + ' ' +
    'skills=' + JSON.stringify(skills) + '. ' +
    'Check that the resume file extracted correctly and the LLM returned valid JSON.'
  );
}

return [{ json: item }];

// BR-4: Deterministic Skill Matching
// BR-5: Experience Calculation Engine
// BR-5b: Deterministic Experience Match Score
// BR-8: Duplicate Detection
// BR-9: Keyword Density Check

const items = $input.all();
const data  = items[0].json;

let job = {
  role:                data.role                || (data.output && data.output.role)                || '',
  skills_required:     data.skills_required     || (data.output && data.output.skills_required)     || [],
  experience_required: data.experience_required || (data.output && data.output.experience_required) || '',
  keywords:            data.keywords            || (data.output && data.output.keywords)            || []
};

let resume = {
  name:       data.name       || (data.output && data.output.name)       || '',
  skills:     data.skills     || (data.output && data.output.skills)     || [],
  experience: data.experience || (data.output && data.output.experience) || [],
  projects:   data.projects   || (data.output && data.output.projects)   || [],
  education:  data.education  || (data.output && data.output.education)  || []
};

// BR-8: Deduplicate resume skills
const rawSkills  = resume.skills || [];
const seenSkills = new Set();
const deduplicatedSkills = [];
for (const skill of rawSkills) {
  const normalized = String(skill).toLowerCase().replace(/[^a-z0-9]/g, '');
  if (!seenSkills.has(normalized)) {
    seenSkills.add(normalized);
    deduplicatedSkills.push(skill);
  }
}
resume.skills = deduplicatedSkills;

// BR-4: Deterministic skill matching
const requiredSkills  = (job.skills_required || []).map(s => String(s).toLowerCase().trim());
const candidateSkills = deduplicatedSkills.map(s => String(s).toLowerCase().trim());

const matchedSkills = [];
const missingSkills = [];

for (const req of requiredSkills) {
  const reqNorm = req.replace(/[^a-z0-9]/g, '');
  const found = candidateSkills.some(cs => {
    const csNorm = cs.replace(/[^a-z0-9]/g, '');
    return cs === req || cs.includes(req) || req.includes(cs) || csNorm === reqNorm;
  });
  if (found) {
    matchedSkills.push(req);
  } else {
    missingSkills.push(req);
  }
}

const deterministicSkillScore = requiredSkills.length > 0
  ? Math.round((matchedSkills.length / requiredSkills.length) * 100)
  : 0;

// BR-5: Experience Calculation
function parseExperienceMonths(expArray) {
  let totalMonths = 0;
  for (const exp of (expArray || [])) {
    const startStr = String(exp.start || exp.startDate || '').toLowerCase().trim();
    const endStr   = String(exp.end   || exp.endDate   || 'present').toLowerCase().trim();

    const parseDate = (str) => {
      if (!str || str === '') return null;
      if (str === 'present' || str === 'current' || str === 'now') return new Date();
      const mmyyyy   = str.match(/(\d{1,2})\/(\d{4})/);
      if (mmyyyy) return new Date(parseInt(mmyyyy[2]), parseInt(mmyyyy[1]) - 1);
      const monthYear = str.match(/([a-z]+)\s+(\d{4})/i);
      if (monthYear) { const d = new Date(str); if (!isNaN(d)) return d; }
      const yyyy = str.match(/\b(\d{4})\b/);
      if (yyyy) return new Date(parseInt(yyyy[1]), 0);
      return null;
    };

    const startDate = parseDate(startStr);
    const endDate   = parseDate(endStr);

    if (startDate && endDate && !isNaN(startDate) && !isNaN(endDate)) {
      const months = (endDate.getFullYear() - startDate.getFullYear()) * 12
                   + (endDate.getMonth() - startDate.getMonth());
      if (months > 0) totalMonths += months;
    }
  }
  return totalMonths;
}

const totalExperienceMonths = parseExperienceMonths(resume.experience);
const totalExperienceYears  = parseFloat((totalExperienceMonths / 12).toFixed(1));

const expRequiredMatch = String(job.experience_required || '').match(/(\d+)/);
const requiredYears    = expRequiredMatch ? parseInt(expRequiredMatch[1]) : 0;
const experienceMet    = totalExperienceYears >= requiredYears;

// BR-5b: Deterministic experience_match score
let experienceMatchScore;
if (requiredYears === 0) {
  experienceMatchScore = 85;
} else {
  const ratio = totalExperienceYears / requiredYears;
  if (ratio >= 1.5)      experienceMatchScore = 95;
  else if (ratio >= 1.0) experienceMatchScore = 85;
  else if (ratio >= 0.8) experienceMatchScore = 72;
  else if (ratio >= 0.6) experienceMatchScore = 60;
  else if (ratio >= 0.4) experienceMatchScore = 45;
  else                   experienceMatchScore = 30;
}

// BR-9: Keyword Density Check
const keywords   = job.keywords && job.keywords.length > 0 ? job.keywords : job.skills_required || [];
const resumeText = JSON.stringify(resume).toLowerCase();
const keywordDensity = {};
for (const kw of keywords) {
  const kwLower  = String(kw).toLowerCase();
  const escaped  = kwLower.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const matches  = resumeText.match(new RegExp(escaped, 'g')) || [];
  keywordDensity[kw] = matches.length;
}
const lowDensityKeywords = keywords.filter(kw => (keywordDensity[kw] || 0) < 2);

return [{
  json: {
    job,
    resume,
    deterministic: {
      matchedSkills,
      missingSkills,
      skillScore:           deterministicSkillScore,
      totalExperienceMonths,
      totalExperienceYears,
      requiredYears,
      experienceMet,
      experienceMatchScore,
      keywordDensity,
      lowDensityKeywords
    }
  }
}];

// BR-15: Application Recommendation
const item = $input.first().json;
const atsOutput = item.output || {};
const score = atsOutput.final_score || 0;

let verdict = '';
let verdictReason = '';

if (score >= 90) {
  verdict = 'Strong Apply';
  verdictReason = 'Excellent match. Your skills and experience align strongly with this role.';
} else if (score >= 75) {
  verdict = 'Apply';
  verdictReason = 'Good match. Minor gaps exist but overall profile is competitive.';
} else if (score >= 60) {
  verdict = 'Apply with Resume Changes';
  verdictReason = 'Moderate match. Address missing skills before applying.';
} else {
  verdict = 'Skip';
  verdictReason = 'Low match. Significant skill or experience gaps detected.';
}

return [{
  json: {
    ...item,
    verdict,
    verdictReason
  }
}];

// BR-2: Memory Retrieval
// FIX (Issue 1): user_id resolution priority:
//   1. user_identifier form field (email or username entered by user) — most stable
//   2. Candidate name from resume (lowercased, spaces→underscores) — fallback
//   3. 'unknown_user' — last resort
//
// This solves the name-collision problem (two 'John Smith' users enter different emails)
// and the instability problem (same user returning gets their history if they use same email).
// Limitation: if user doesn't fill in email, name-based ID is still used (acceptable for portfolio).

const genPayload = $node['Prepare Generation Payload'].json;
const resumeName = genPayload.resume.name || '';

// Pull user_identifier from the form submission (flows through binary/json)
// It was submitted in Start Application but not explicitly passed forward in set nodes.
// We read it directly from the trigger via $execution context — not available.
// Instead: it is present in the n8n execution data on the trigger node.
// Safest approach: read from $node['Start Application'] which is accessible via node reference.
let rawIdentifier = '';
try {
  rawIdentifier = $node['Start Application'].json.user_identifier || '';
} catch(e) {
  rawIdentifier = '';
}

// Normalise: lowercase, trim, replace spaces with underscores, strip non-alphanumeric
const normalise = (s) => String(s).toLowerCase().trim().replace(/\s+/g, '_').replace(/[^a-z0-9_.@-]/g, '');

const USER_ID = rawIdentifier
  ? normalise(rawIdentifier)
  : (resumeName ? normalise(resumeName) : 'unknown_user');

const staticData = $getWorkflowStaticData('global');
const allRecords = staticData.user_preferences || [];

const userRecords = allRecords
  .filter(r => r.user_id === USER_ID)
  .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));

const latest = userRecords.length > 0 ? userRecords[0] : null;

return [{
  json: {
    ...(latest || {}),
    _resolved_user_id: USER_ID
  }
}];

// BR-1: Smart Review Processor
// Priority rules (deterministic, not user-driven):
//   HIGH   → always accepted
//   MEDIUM → top 2 accepted, rest rejected
//   LOW    → always rejected
//
// BR-2: Reads memory context from Load User Memory output

const suggestions = $node['Prepare Generation Payload'].json.suggestions || [];

const highPriority   = suggestions.filter(s => (s.priority || '').toLowerCase() === 'high');
const mediumPriority = suggestions.filter(s => (s.priority || '').toLowerCase() === 'medium');
const lowPriority    = suggestions.filter(s => (s.priority || '').toLowerCase() === 'low');

const acceptedSuggestions = [
  ...highPriority,
  ...mediumPriority.slice(0, 2)
];
const rejectedSuggestions = [
  ...mediumPriority.slice(2),
  ...lowPriority
];

// Read memory from Load User Memory output
let pastMemory = null;
try {
  const memItems = $input.all();
  if (memItems && memItems.length > 0 && memItems[0].json && memItems[0].json.user_id) {
    pastMemory = memItems[0].json;
  }
} catch(e) {}

const parseStoredArray = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') {
    try { const p = JSON.parse(value || '[]'); return Array.isArray(p) ? p : []; } catch(e) { return []; }
  }
  return [];
};

const memoryContext = pastMemory ? {
  past_accepted:     parseStoredArray(pastMemory.accepted_suggestions),
  past_rejected:     parseStoredArray(pastMemory.rejected_suggestions),
  past_ats_score:    pastMemory.ats_score  || null,
  past_job_role:     pastMemory.job_role   || null,
  preference_scores: (() => {
    try { return JSON.parse(pastMemory.preference_scores || '{}'); } catch(e) { return {}; }
  })(),
  resume_version: (pastMemory.resume_version || 0) + 1
} : {
  past_accepted:     [],
  past_rejected:     [],
  past_ats_score:    null,
  past_job_role:     null,
  preference_scores: {},
  resume_version:    1
};

return [{
  json: {
    accepted_suggestions: acceptedSuggestions,
    rejected_suggestions: rejectedSuggestions,
    memory_context:       memoryContext
  }
}];

// BR-7: Resume Validation Layer
// Hard error on critical missing sections; soft warning for optional ones.
const item = $input.first().json;
const resume = item.output || {};

const warnings      = [];
const criticalErrors = [];

if (!resume.summary || String(resume.summary).trim() === '') {
  warnings.push('Missing Summary section.');
}
if (!resume.skills || resume.skills.length === 0) {
  criticalErrors.push('Missing Skills section — resume is not usable without skills.');
}
if (!resume.experience || resume.experience.length === 0) {
  criticalErrors.push('Missing Experience section — resume is not usable without experience.');
}
if (!resume.education || resume.education.length === 0) {
  warnings.push('Missing Education section.');
}
if (!resume.projects || resume.projects.length === 0) {
  warnings.push('Missing Projects section (optional but recommended).');
}

if (criticalErrors.length > 0) {
  throw new Error(
    'Resume Validation FAILED (critical): ' + criticalErrors.join(' | ') +
    (warnings.length > 0 ? ' | Warnings: ' + warnings.join(' | ') : '')
  );
}

return [{
  json: {
    ...item,
    resume_validation: {
      passed:          warnings.length === 0,
      warnings,
      critical_errors: criticalErrors
    }
  }
}];

// FIX (Issue 3): Consolidated storage — user_preferences written to staticData ONLY.
// The user_preferences DataTable CREATE node has been removed.
// application_summary and audit_log continue to use DataTable (correct — separate concern).
//
// FIX (Issue 1): user_id comes from _resolved_user_id (email-first, name-fallback).
// Memory growth cap: max 1000 records, oldest removed when exceeded.

const staticData = $getWorkflowStaticData('global');

if (!staticData.user_preferences) {
  staticData.user_preferences = [];
}

const record = {
  user_id:                    $input.item.json.user_id,
  accepted_suggestions:       $input.item.json.accepted_suggestions,
  rejected_suggestions:       $input.item.json.rejected_suggestions,
  ats_score:                  $input.item.json.ats_score,
  ats_confidence:             $input.item.json.ats_confidence,
  job_role:                   $input.item.json.job_role,
  verdict:                    $input.item.json.verdict,
  resume_version:             $input.item.json.resume_version,
  preference_scores:          $input.item.json.preference_scores,
  resume_validation_warnings: $input.item.json.resume_validation_warnings,
  timestamp:                  $input.item.json.timestamp
};

staticData.user_preferences.push(record);

const MAX_RECORDS = 1000;
while (staticData.user_preferences.length > MAX_RECORDS) {
  staticData.user_preferences.shift();
}

return [{
  json: {
    status:        'Memory saved',
    total_records: staticData.user_preferences.length,
    latest:        record
  }
}];

// Build Resume HTML for PDF output
const item = $input.first().json;
const r = item.output || {};
const reviewData = $node['Prepare Review Data'].json;

const esc = (s) => String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const skillsList = (r.skills || []).map(s =>
  `<span style="display:inline-block;background:#f0f4ff;border:1px solid #c7d2fe;border-radius:4px;padding:2px 10px;margin:2px 4px 2px 0;font-size:12px;color:#3730a3;">${esc(s)}</span>`
).join('');

const expItems = (r.experience || []).map(exp => {
  if (typeof exp === 'string') return `<li style="margin-bottom:6px;">${esc(exp)}</li>`;
  return `<li style="margin-bottom:10px;"><strong>${esc(exp.title || '')}</strong> · ${esc(exp.company || '')} <span style="color:#6b7280;font-size:12px;">${esc(exp.start || '')}–${esc(exp.end || 'Present')}</span><br/><span style="font-size:13px;color:#374151;">${esc(exp.description || '')}</span></li>`;
}).join('');

const projItems = (r.projects || []).map(p =>
  `<li style="margin-bottom:6px;">${esc(typeof p === 'string' ? p : JSON.stringify(p))}</li>`
).join('');
const eduItems = (r.education || []).map(e =>
  `<li style="margin-bottom:6px;">${esc(typeof e === 'string' ? e : JSON.stringify(e))}</li>`
).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"/><title>Resume — ${esc(reviewData.candidate_name)}</title></head>
<body style="font-family:Arial,sans-serif;max-width:800px;margin:40px auto;color:#111;line-height:1.6;">
  <div style="border-bottom:3px solid #4f46e5;padding-bottom:12px;margin-bottom:24px;">
    <h1 style="margin:0;font-size:26px;color:#1e1b4b;">${esc(r.header || reviewData.candidate_name)}</h1>
    <p style="margin:4px 0 0;font-size:13px;color:#6b7280;">ATS Score: ${reviewData.ats_score || 'N/A'} · Role: ${esc(reviewData.job_role)} · Version: ${reviewData.memory_context && reviewData.memory_context.resume_version ? reviewData.memory_context.resume_version : 1}</p>
  </div>
  ${r.summary ? `<section style="margin-bottom:20px;"><h2 style="font-size:15px;color:#4f46e5;border-bottom:1px solid #e5e7eb;padding-bottom:4px;margin-bottom:8px;">SUMMARY</h2><p style="margin:0;font-size:13px;">${esc(r.summary)}</p></section>` : ''}
  ${skillsList ? `<section style="margin-bottom:20px;"><h2 style="font-size:15px;color:#4f46e5;border-bottom:1px solid #e5e7eb;padding-bottom:4px;margin-bottom:8px;">SKILLS</h2><div>${skillsList}</div></section>` : ''}
  ${expItems ? `<section style="margin-bottom:20px;"><h2 style="font-size:15px;color:#4f46e5;border-bottom:1px solid #e5e7eb;padding-bottom:4px;margin-bottom:8px;">EXPERIENCE</h2><ul style="padding-left:16px;margin:0;">${expItems}</ul></section>` : ''}
  ${projItems ? `<section style="margin-bottom:20px;"><h2 style="font-size:15px;color:#4f46e5;border-bottom:1px solid #e5e7eb;padding-bottom:4px;margin-bottom:8px;">PROJECTS</h2><ul style="padding-left:16px;margin:0;">${projItems}</ul></section>` : ''}
  ${eduItems ? `<section style="margin-bottom:20px;"><h2 style="font-size:15px;color:#4f46e5;border-bottom:1px solid #e5e7eb;padding-bottom:4px;margin-bottom:8px;">EDUCATION</h2><ul style="padding-left:16px;margin:0;">${eduItems}</ul></section>` : ''}
</body>
</html>`;

return [{ json: { html_resume: html, candidate_name: reviewData.candidate_name } }];

// Build Cover Letter HTML for PDF output
const item = $input.first().json;
const reviewData = $node['Prepare Review Data'].json;
const coverLetter = reviewData.cover_letter || '';

const esc = (s) => String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const bodyHtml = esc(coverLetter).replace(/\n/g, '<br/>');

const html = `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"/><title>Cover Letter — ${esc(reviewData.candidate_name)}</title></head>
<body style="font-family:Arial,sans-serif;max-width:800px;margin:40px auto;color:#111;line-height:1.8;">
  <div style="border-bottom:3px solid #4f46e5;padding-bottom:12px;margin-bottom:32px;">
    <h1 style="margin:0;font-size:22px;color:#1e1b4b;">Cover Letter</h1>
    <p style="margin:4px 0 0;font-size:13px;color:#6b7280;">${esc(reviewData.candidate_name)} · ${esc(reviewData.job_role)}</p>
  </div>
  <div style="font-size:14px;color:#1f2937;">${bodyHtml}</div>
</body>
</html>`;

return [{ json: { html_cover_letter: html, candidate_name: reviewData.candidate_name } }];
